                    >
                      {(() => { const Icon = link.icon; return <Icon size={16} className="text-gray-400 flex-shrink-0" />; })()}
                      {link.name}
                      {isActive(link.path) && (
                        <span className="ml-auto w-2 h-2 bg-red-600 rounded-full" />
