              <SidebarItem to="config-inicio" icon={Settings} label="Personalizar Inicio" active={isActive('config-inicio')} />
            </>
          )}
        </nav>

        {/* Perfil y Logout con Glassmorphism */}
        <div className="mt-6 pt-6 border-t border-white/5">
