} from 'lucide-react';

const Toast = Swal.mixin({
    toast: true,
    position: 'top-end',
    showConfirmButton: false,
    timer: 3000,
    timerProgressBar: true
});

const AdminCarrusel = () => {
    const [slides, setSlides] = useState([]);
