                                    <option value="circular">­ƒôä Circular Administrativa</option>
                                    <option value="urgente">­ƒÜ¿ Alerta Urgente</option>
                                </select>
                            </div>
                        </div>
                        <div className="space-y-2 group">
                            <label className="text-[10px] font-black text-gray-400 uppercase ml-4 tracking-widest group-focus-within:text-[#003087] transition-colors">Mensaje Oficial Detallado</label>
                            <textarea placeholder="Escribe el contenido detallado aqu├¡..." className="w-full p-6 rounded-[2rem] bg-slate-50/50 border border-transparent focus:border-[#003087] focus:bg-white focus:ring-4 focus:ring-blue-50 font-bold text-gray-600 outline-none transition-all h-48 resize-none text-lg leading-relaxed" value={descripcion} onChange={e => setDescripcion(e.target.value)} required></textarea>
